  YGNodeInsertChild(root, root_child1, 1);

  YGNodeRef root_child2 = YGNodeNewWithConfig(config);
  YGNodeStyleSetPadding(root_child2, YGEdgeLeft, 30);
  YGNodeStyleSetPadding(root_child2, YGEdgeTop, 30);
  YGNodeStyleSetPadding(root_child2, YGEdgeRight, 30);
  YGNodeStyleSetPadding(root_child2, YGEdgeBottom, 30);
  YGNodeInsertChild(root, root_child2, 2);

  YGNodeRef root_child3 = YGNodeNewWithConfig(config);
  YGNodeStyleSetMinWidth(root_child3, 40);
  YGNodeInsertChild(root, root_child3, 3);

  YGNodeRef root_child4 = YGNodeNewWithConfig(config);
  YGNodeStyleSetBorder(root_child4, YGEdgeLeft, 10);
  YGNodeStyleSetBorder(root_child4, YGEdgeTop, 10);
  YGNodeStyleSetBorder(root_child4, YGEdgeRight, 10);
  YGNodeStyleSetBorder(root_child4, YGEdgeBottom, 10);
  YGNodeInsertChild(root, root_child4, 4);
  YGNodeCalculateLayout(root, YGUndefined, YGUndefined, YGDirectionLTR);

